import { readFileSync } from "node:fs";

function assert(name, condition) {
  if (!condition) throw new Error(name);
  console.log(`ok - ${name}`);
}

const workingState = readFileSync("src/working-state.ts", "utf8");
const sessionManager = readFileSync("src/sessionManager.ts", "utf8");
const relay = readFileSync("src/commands/relay.ts", "utf8");
const runPrompt = readFileSync("src/run-prompt.ts", "utf8");

assert("relay task ledger type exists", workingState.includes("export interface RelayTaskRecord"));
assert("relay task ledger persists under MEMORY_DIR", workingState.includes("relay-task-ledger.json"));
assert("relay task upsert API exists", workingState.includes("export async function upsertRelayTask("));
assert("relay task input API exists", workingState.includes("export async function addRelayTaskInput("));
assert("active relay tasks can be formatted for preamble", workingState.includes("formatActiveRelayTasksForPreamble"));

assert("session creation imports active relay task formatter", sessionManager.includes("formatActiveRelayTasksForPreamble"));
assert("session creation appends relay task block once", sessionManager.includes("breakdown.text + workingStateBlock + archiveBlock + relayTaskBlock"));

const relayInputStart = relay.indexOf("// RELAY_INPUT");
assert("RELAY_INPUT branch exists", relayInputStart >= 0);
const relayInputEnd = relay.indexOf("// RELAY_OUTPUT", relayInputStart);
assert("RELAY_INPUT branch end found", relayInputEnd > relayInputStart);
const relayInputBlock = relay.slice(relayInputStart, relayInputEnd);
assert("RELAY_INPUT updates task ledger", relayInputBlock.includes("addRelayTaskInput(from, localPath)"));
assert("RELAY_INPUT uses relay group session", relayInputBlock.includes("const relayChatId = config.relay!.groupChatId;"));
assert("RELAY_INPUT no longer injects into owner private session", !relayInputBlock.includes("sessions.get(ownerChatId, ownerChatId)"));
assert("RELAY_INPUT sends silent meta to relay group", relayInputBlock.includes('session, prompt, { kind: "meta", silent: true }'));

assert("incoming delegate attachment records ledger", relay.includes('direction: "incoming"') && relay.includes("attachmentPath: localPath"));
assert("incoming delegate text records ledger", relay.includes("delegate from ${msg.from}") && relay.includes("injectRelayTaskNoticeToOwner("));
assert("incoming result closes outgoing ledger task", relay.includes('direction: "outgoing"') && relay.includes("resultSummary: r.summary"));

assert("outgoing relay delegates record ledger", runPrompt.includes('direction: "outgoing"') && runPrompt.includes("attachmentPath: session._lastUploadPath"));
assert("relay replies record incoming results", runPrompt.includes('direction: "incoming"') && runPrompt.includes("resultSummary: rr.payload.summary"));
assert("relay output files attach to ledger", runPrompt.includes("addRelayTaskOutput(rf.target, rf.path)"));

console.log("relay context ledger semantics OK");

